//#region extensions/qa-lab/src/live-timeout.ts
function isAnthropicModel(modelRef) {
	return modelRef.startsWith("anthropic/");
}
function isOpenAiModel(modelRef) {
	return modelRef.startsWith("openai/");
}
function isGptFiveModel(modelRef) {
	return isOpenAiModel(modelRef) && modelRef.slice(7).startsWith("gpt-5");
}
function isClaudeOpusModel(modelRef) {
	return isAnthropicModel(modelRef) && modelRef.includes("claude-opus");
}
function resolveQaLiveTurnTimeoutMs(profile, fallbackMs, modelRef = profile.primaryModel) {
	if (profile.providerMode === "mock-openai") return fallbackMs;
	if (isClaudeOpusModel(modelRef)) return Math.max(fallbackMs, 24e4);
	if (isAnthropicModel(modelRef)) return Math.max(fallbackMs, 18e4);
	if (isGptFiveModel(modelRef)) return Math.max(fallbackMs, 36e4);
	return Math.max(fallbackMs, 12e4);
}
//#endregion
export { resolveQaLiveTurnTimeoutMs as t };
